/**
 * @fileoverview Drawer definition for JIT pipeline.
 * @module module/Drawer.def
 */

import { PART } from './Drawer/constants.js';

export const DrawerDef = {
    name: 'Drawer',
    tag: 'rui-drawer',

    tokens: {
        prefix: 'dw',
        tokens: {
            'bg':              { ref: 'color.bg',       description: 'Panel background' },
            'border':          { ref: 'color.border',   description: 'Separator color' },
            'shadow':          { ref: 'shadow.lg',      description: 'Panel shadow' },
            'radius':          { ref: 'radius.sm',      description: 'Close button radius' },
            'px':              { value: '1.25rem',      description: 'Horizontal padding' },
            'py':              { value: '1rem',         description: 'Body vertical padding' },
            'header-py':       { value: '0.75rem',      description: 'Header padding' },
            'footer-py':       { value: '0.75rem',      description: 'Footer padding' },
            'title-size':      { ref: 'font.size-base', description: 'Title font size' },
            'title-color':     { ref: 'color.text',     description: 'Title color' },
            'close-color':     { ref: 'color.text-secondary', description: 'Close icon color' },
            'close-hover-bg':  { ref: 'color.hover',    description: 'Close hover background' },
        },
    },

    states: {
        initial: 'closed',
        states: {
            closed: { on: { OPEN: 'open' } },
            open:   { on: { CLOSE: 'closed' } },
        },
    },

    jitParts: {
        [PART.ROOT]: PART.ROOT,
        [PART.BACKDROP]: PART.BACKDROP,
        [PART.PANEL]: PART.PANEL,
        [PART.HEADER]: PART.HEADER,
        [PART.BODY]: PART.BODY,
        [PART.FOOTER]: PART.FOOTER,
        [PART.TITLE]: PART.TITLE,
        [PART.CLOSE]: PART.CLOSE,
    },

    observedAttrs: ['position', 'width', 'height', 'title', 'closable', 'open'],

    attrMap: { open: 'opened' },

    handlers: {
        open: { action: 'OPEN', transform: Boolean },
    },
};
