/**
 * @fileoverview Drawer component — modular entry point.
 * @module module/Drawer
 */

import { default as razyui } from '../../index.js';
import { DrawerDef as DEF } from '../Drawer.def.js';
import { DEFAULTS, CLS } from './constants.js';
import { setupDOM, showPanel, hidePanel, cleanupDOM } from './view.js';
import { emitEvent } from '../shared/emitEvent.js';
import { zIndexRegistry } from '../shared/ZIndexRegistry.js';

const Drawer = class {
    #root     = null;
    #destroyed = false;
    #config   = {};
    #els      = {};
    #isOpen   = false;
    #eventAC       = new AbortController();

    constructor(selector, config = {}) {
        const root = razyui(selector);
        if (!root.length) { console.warn('Drawer: element not found →', selector); return; }

        this.#root   = root;
        this.#config = { ...DEFAULTS, ...config };

        this.#els = setupDOM(root, this.#config);
        this.#init();
    }

    /* ---- events ---- */
    #init() {
        const sig = { signal: this.#eventAC.signal };

        if (this.#els.closeBtn) {
            this.#els.closeBtn.addEventListener('click', () => this.close(), sig);
        }

        if (this.#config.closeOnBackdrop) {
            this.#els.backdrop.addEventListener('click', () => this.close(), sig);
        }

        // ESC key
        document.addEventListener('keydown', (e) => {
            if (e.key === 'Escape' && this.#isOpen) this.close();
        }, sig);
    }

    /* ---- public API ---- */
    open() {
        if (this.#isOpen) return;
        this.#isOpen = true;
        zIndexRegistry.acquire(this.#root[0]);
        this.#root.addClass(CLS.OPEN);
        showPanel(this.#els.panel, this.#els.backdrop);
        document.body.style.overflow = 'hidden';
        emitEvent(this.#root[0], 'open');
    }

    close() {
        if (!this.#isOpen) return;
        this.#isOpen = false;
        this.#root.removeClass(CLS.OPEN);
        zIndexRegistry.release(this.#root[0]);
        hidePanel(this.#els.panel, this.#els.backdrop, this.#config.position, this.#config.width, this.#config.height);
        document.body.style.overflow = '';
        emitEvent(this.#root[0], 'close');
    }

    toggle() {
        this.#isOpen ? this.close() : this.open();
    }

    get isOpen() { return this.#isOpen; }

    get contentEl() { return this.#els.body; }

    getControl() {
        const self = this;
        return {
            get opened()    { return self.isOpen; },
            set opened(v)   { v ? self.open() : self.close(); },
            get title()     { const t = self.#els.panel?.querySelector?.('.' + CLS.TITLE); return t ? t.textContent : ''; },
            set title(v)    { const t = self.#els.panel?.querySelector?.('.' + CLS.TITLE); if (t) t.textContent = v ?? ''; },
            get closable()  { return self.#config.closable; },
            set closable(v) { self.#config.closable = !!v; if (self.#els.closeBtn) self.#els.closeBtn.style.display = v ? '' : 'none'; },
            get width()     { return self.#config.width; },
            set width(v)    { self.#config.width = v; self.#els.panel.style.width = v; },
            get height()    { return self.#config.height; },
            set height(v)   { self.#config.height = v; self.#els.panel.style.height = v; },
            open:    () => self.open(),
            close:   () => self.close(),
            toggle:  () => self.toggle(),
            get isOpen()    { return self.isOpen; },
            get contentEl() { return self.contentEl; },
            destroy: () => self.destroy(),
            get element() { return self.#root[0]; },
            get destroyed() { return self.#destroyed; },
        };
    }

    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        this.#eventAC?.abort();
        zIndexRegistry.release(this.#root[0]);
        cleanupDOM(this.#root);
    }
};

export default Drawer;
