/**
 * @fileoverview Drawer view — DOM setup & effects.
 * @module module/Drawer/view
 */

import { CLS, PART } from './constants.js';

/* -------- position helpers -------- */
const POSITION_STYLES = {
    left:   (w) => ({ top: '0', left: '0', bottom: '0', width: w, transform: 'translateX(-100%)' }),
    right:  (w) => ({ top: '0', right: '0', bottom: '0', width: w, transform: 'translateX(100%)' }),
    top:    (_, h) => ({ top: '0', left: '0', right: '0', height: h, transform: 'translateY(-100%)' }),
    bottom: (_, h) => ({ bottom: '0', left: '0', right: '0', height: h, transform: 'translateY(100%)' }),
};

const OPEN_TRANSFORM = 'translate(0,0)';

/* -------- close SVG -------- */
const CLOSE_SVG = `<svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 16 16" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><line x1="4" y1="4" x2="12" y2="12"/><line x1="12" y1="4" x2="4" y2="12"/></svg>`;

/* -------- setup -------- */
export function setupDOM(root, config) {
    const el = root[0];
    el.className = CLS.ROOT;
    PART.ROOT.apply(root);

    /* backdrop */
    const $backdrop = PART.BACKDROP.create();
    root.append($backdrop);

    /* panel */
    const $panel = PART.PANEL.create();
    root.append($panel);
    const panel = $panel[0];

    // Apply position styles
    const pos = POSITION_STYLES[config.position] || POSITION_STYLES.right;
    Object.assign(panel.style, pos(config.width, config.height));

    /* header */
    const $header = PART.HEADER.create();
    $panel.append($header);

    const $title = PART.TITLE.create();
    $title.text(config.title || '');
    $header.append($title);

    let closeBtn = null;
    if (config.closable) {
        const $close = PART.CLOSE.create({
            type: 'button',
            'aria-label': 'Close',
        });
        $close[0].innerHTML = CLOSE_SVG;
        $header.append($close);
        closeBtn = $close[0];
    }

    /* body */
    const $body = PART.BODY.create();
    $panel.append($body);

    return { backdrop: $backdrop[0], panel, closeBtn, body: $body[0], $panel };
}

export function showPanel(panel, backdrop) {
    panel.style.transform = OPEN_TRANSFORM;
    backdrop.style.opacity = '1';
}

export function hidePanel(panel, backdrop, position, width, height) {
    const pos = POSITION_STYLES[position] || POSITION_STYLES.right;
    const styles = pos(width, height);
    panel.style.transform = styles.transform;
    backdrop.style.opacity = '0';
}

export function cleanupDOM(root) {
    root.removeClass(CLS.ROOT);
}
